solution_code:
#include <cstddef>
#include <iostream>

int main()
{
    constexpr std::size_t rows{ 3 };
    constexpr std::size_t cols{ 5 };
    int matrix[rows][cols]{};

    for (std::size_t r{ 0 }; r < rows; ++r)
        for (std::size_t c{ 0 }; c < cols; ++c)
            std::cin >> matrix[r][c];

    for (std::size_t c{ 0 }; c < cols; ++c)
    {
        int colMax{ matrix[0][c] };
        for (std::size_t r{ 1 }; r < rows; ++r)
        {
            if (matrix[r][c] > colMax)
                colMax = matrix[r][c];
        }
        if (c > 0)
            std::cout << ' ';
        std::cout << colMax;
    }
    std::cout << '\n';

    return 0;
}
